css:
/* Basic Styling */
body {
  font-family: Arial, sans-serif;
  margin: 0;
  padding: 0;
  background-color: #f4f4f4;
}

/* Letterhead */
.letterhead {
  text-align: center;
  padding: 20px;
  background-color: #2a3d66;
  color: white;
}

.letterhead h1 {
  margin: 0;
  font-size: 36px;
}

.letterhead p {
  margin: 5px;
  font-size: 16px;
}

/* Main Contract Container */
.contract-container {
  max-width: 800px;
  margin: 0 auto;
  background-color: white;
  padding: 20px;
  box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1);
  border-radius: 8px;
}

/* Title and Header */
h2, h4 {
  text-align: center;
}

h3 {
  color: #2a3d66;
  border-bottom: 2px solid #2a3d66;
  padding-bottom: 5px;
  margin-top: 40px;
}

/* Table Styling */
table {
  width: 100%;
  margin: 20px 0;
  border-collapse: collapse;
}

table td {
  padding: 8px;
  border: 1px solid #ddd;
}

/* Content Box */
.contract-content {
  border: 1px solid #ddd;
  padding: 15px;
  margin-top: 20px;
  background-color: #f9f9f9;
}

/* Signature Section */
.signature-section td {
  text-align: center;
  padding: 40px 0;
}

.signature-section td p {
  margin: 0;
}

/* Page Break */
.page-break {
  page-break-before: always;
}

/* For Print */
@media print {
  .page-break {
    page-break-before: always;
  }
}
